class Solution:
    def isItPossible(self, word1, word2):
        w1 = list(word1)
        w2 = list(word2)
        for i in range(len(w1)):
            for j in range(len(w2)):
                w1[i], w2[j] = w2[j], w1[i]
                equal = len(set(w1)) == len(set(w2))
                w1[i], w2[j] = w2[j], w1[i]
                if equal:
                    return True
        return False

