var isItPossible = function(word1, word2) {
    const count1 = new Array(26).fill(0);
    const count2 = new Array(26).fill(0);
    for (const ch of word1) count1[ch.charCodeAt(0) - 97]++;
    for (const ch of word2) count2[ch.charCodeAt(0) - 97]++;
    for (let c1 = 0; c1 < 26; c1++) {
        if (count1[c1] === 0) continue;
        for (let c2 = 0; c2 < 26; c2++) {
            if (count2[c2] === 0) continue;
            const new1 = count1.slice();
            const new2 = count2.slice();
            new1[c1] -= 1;
            new1[c2] += 1;
            new2[c2] -= 1;
            new2[c1] += 1;
            const distinct1 = new1.filter(v => v > 0).length;
            const distinct2 = new2.filter(v => v > 0).length;
            if (distinct1 === distinct2) return true;
        }
    }
    return false;
};
